const body = $json.body || $json;
const text = body.message || body.event_text || body.text || '';
const source = body.source || 'class_demo';
const consent = body.consent === true || body.consent === 'true';
const language = body.language || 'he';
const prompt = `אתה סוכן ניווט ותמיכה ראשונית עבור משוחררים/ות עם מצוקה נפשית או פוסט-טראומה.

חשוב: אינך מטפל, אינך מאבחן, אינך נותן טיפול רפואי, ואינך מחליף איש מקצוע. המטרה שלך היא להבין צורך, לזהות סיכון, להציע צעד בטוח, ולהפנות לגורם מתאים.

החזר JSON בלבד. בלי הסברים מחוץ ל-JSON.

רמות סיכון:
green = מידע כללי, ניווט זכויות, קושי בירוקרטי, חיפוש גורם סיוע.
yellow = מצוקה משמעותית, קושי לתפקד, צורך בליווי אנושי, אבל ללא סכנה מיידית.
red = סימנים לסיכון, יאוש חריף, בידוד קיצוני, אלימות, שימוש מסוכן בחומרים, או משפטים שמרמזים על פגיעה עצמית בלי תוכנית ברורה.
critical = סכנה מיידית לעצמו או לאחרים, תוכנית פגיעה, אמצעים זמינים, או אמירה ישירה על כוונה לפגוע.

חוקי בטיחות:
- אם יש חשד לסכנה מיידית: risk=critical, recommended_action=crisis_escalation, needs_human_review=true.
- אל תציע טיפול קליני.
- אל תבטיח מימון, הכרה, זכאות או תור.
- אל תאסוף פרטים מזהים מעבר למה שנדרש.
- אם אין הסכמה לעיבוד מידע, אל תשמור מידע אישי.
- התגובה חייבת להיות מחזקת, לא שיפוטית, פשוטה, וקצרה.

פורמט JSON:
{
  "need_type": "benefits_navigation | therapy_access | social_worker | funding | peer_support | crisis | bureaucracy | unknown",
  "risk": "green | yellow | red | critical",
  "summary": "סיכום קצר בעברית",
  "recommended_action": "info_pack | human_callback | eligibility_map | provider_match | crisis_escalation | ask_clarifying_question",
  "response_to_user": "תגובה אמפתית וקצרה בעברית",
  "next_step": "הצעד הבא המוצע",
  "needs_human_review": true,
  "data_minimization_note": "מה לא לשמור או לשמור מינימום",
  "agent_needed": "intake | rights | therapy_match | funding | crisis_guard | followup",
  "reason": "סיבה קצרה לסיווג"
}

הודעה מהמשתמש:
${text}

מקור: ${source}
הסכמה לעיבוד מידע: ${consent}
שפה: ${language}`;

return [{ json: { model: body.model || 'llama3.1:8b', stream: false, prompt, original: body } }];

function safeParse(raw) {
  if (!raw) throw new Error('empty model response');
  let txt = String(raw).trim();
  txt = txt.replace(/^```json/i, '').replace(/^```/i, '').replace(/```$/i, '').trim();
  const start = txt.indexOf('{');
  const end = txt.lastIndexOf('}');
  if (start >= 0 && end > start) txt = txt.slice(start, end + 1);
  return JSON.parse(txt);
}
try {
  const parsed = safeParse($json.response);
  const risk = parsed.risk || 'red';
  const needs = parsed.needs_human_review === true || ['red','critical'].includes(risk);
  return [{ json: { status: needs ? 'human_review_required' : 'safe_auto_response', ai_result: parsed, raw_ollama: $json.response } }];
} catch (e) {
  return [{ json: { status: 'human_review_required', ai_result: { need_type: 'unknown', risk: 'red', summary: 'המודל לא החזיר JSON תקין', recommended_action: 'human_callback', response_to_user: 'קיבלנו את הפנייה. נציג אנושי יעבור עליה לפני כל פעולה.', next_step: 'בדיקה ידנית', needs_human_review: true, data_minimization_note: 'לא לשמור מידע אישי עד בדיקה', agent_needed: 'intake', reason: e.message }, raw_ollama: $json.response || null } }];
}
